import json

# Sample of stocks to process - I'll build this systematically
# From my manual queries:
# AIN: 143 up, 101 down - GOOD
# AIV: 118 up, 128 down - BAD  
# AL: 131 up, 117 down - GOOD

stocks_analysis = {
    'AIN': {'up': 143, 'down': 101, 'name': 'Albany International Corporation'},
    'AL': {'up': 131, 'down': 117, 'name': 'Air Lease Corporation'},
}

print('__RESULT__:')
print(json.dumps({
    'current_top': sorted(
        [(symbol, data['up'] - data['down'], data['name']) 
         for symbol, data in stocks_analysis.items()],
        key=lambda x: x[1],
        reverse=True
    )[:5]
}))

